            interface $Exports {
                /**
                 * An adaptive dialog container.
                 *
                 * <picture>
                 *   <source srcset="dialog-floating-dark.png" media="(prefers-color-scheme: dark)">
                 *   <img src="dialog-floating.png" alt="dialog-floating">
                 * </picture>
                 * <picture>
                 *   <source srcset="dialog-bottom-dark.png" media="(prefers-color-scheme: dark)">
                 *   <img src="dialog-bottom.png" alt="dialog-bottom">
                 * </picture>
                 *
                 * `AdwDialog` is similar to a window, but is shown within another window. It
                 * can be used with {@link Window} and {@link ApplicationWindow}, use
                 * {@link Dialog.present} to show it.
                 *
                 * `AdwDialog` is not resizable. Use the {@link Dialog.contentWidth} and
                 * {@link Dialog.contentHeight} properties to set its size, or set
                 * {@link Dialog.followsContentSize} to `TRUE` to make the dialog track the
                 * content's size as it changes. `AdwDialog` can never be larger than its parent
                 * window.
                 *
                 * `AdwDialog` can be presented as a centered floating window or a bottom sheet.
                 * By default it's automatic depending on the available size.
                 * {@link Dialog.presentationMode} can be used to change that.
                 *
                 * `AdwDialog` can be closed via {@link Dialog.close}.
                 *
                 * When presented as a bottom sheet, `AdwDialog` can also be closed via swiping
                 * it down.
                 *
                 * The {@link Dialog.canClose} can be used to prevent closing. In that case,
                 * {@link Dialog.SignalSignatures["close-attempt"]} gets emitted instead.
                 *
                 * Use {@link Dialog.force_close} to close the dialog even when `can-close` is set to
                 * `FALSE`.
                 *
                 * `AdwDialog` is transient and doesn't integrate with the window below it, for
                 * example it's not possible to collapse it into a bottom bar. See
                 * {@link BottomSheet} for persistent and more tightly integrated bottom sheets.
                 *
                 * ## Header Bar Integration
                 *
                 * When placed inside an `AdwDialog`, {@link HeaderBar} will display the dialog
                 * title instead of window title. It will also adjust the decoration layout to
                 * ensure it always has a close button and nothing else. Set
                 * {@link HeaderBar.showStartTitleButtons} and
                 * {@link HeaderBar.showEndTitleButtons} to `FALSE` to remove it if it's
                 * unwanted.
                 *
                 * ## Breakpoints
                 *
                 * `AdwDialog` can be used with {@link Breakpoint} the same way as
                 * {@link BreakpointBin}. Refer to that widget's documentation for details.
                 *
                 * Like `AdwBreakpointBin`, if breakpoints are used, `AdwDialog` doesn't have a
                 * minimum size, and {@link Gtk.Widget.widthRequest} and
                 * {@link Gtk.Widget.heightRequest} properties must be set manually.
                 * @since 1.5
                 */
                Dialog: DialogClass
            }
            

