            interface HeaderBarClass extends Omit<Gtk.WidgetClass, "new"> {
                readonly $gtype: GObject.GType<HeaderBar>
                readonly prototype: HeaderBar

                new (props?: Partial<GObject.ConstructorProps<HeaderBar>>): HeaderBar
                /**
                 * Creates a new `AdwHeaderBar`.
                 * @returns the newly created `AdwHeaderBar`.
                 */
                "new"(): HeaderBar
            }

            interface $Exports {
                /**
                 * A title bar widget.
                 *
                 * <picture>
                 *   <source srcset="header-bar-dark.png" media="(prefers-color-scheme: dark)">
                 *   <img src="header-bar.png" alt="header-bar">
                 * </picture>
                 *
                 * `AdwHeaderBar` is similar to {@link Gtk.HeaderBar}, but provides additional
                 * features compared to it. Refer to `GtkHeaderBar` for details. It is typically
                 * used as a top bar within {@link ToolbarView}.
                 *
                 * ## Dialog Integration
                 *
                 * When placed inside an {@link Dialog}, `AdwHeaderBar` will display the dialog
                 * title instead of window title. It will also adjust the decoration layout to
                 * ensure it always has a close button and nothing else. Set
                 * {@link HeaderBar.showStartTitleButtons} and
                 * {@link HeaderBar.showEndTitleButtons} to `FALSE` to remove it if it's
                 * unwanted.
                 *
                 * ## Navigation View Integration
                 *
                 * When placed inside an {@link NavigationPage}, `AdwHeaderBar` will display the
                 * page title instead of window title.
                 *
                 * When used together with {@link NavigationView} or {@link NavigationSplitView},
                 * it will also display a back button that can be used to go back to the previous
                 * page. The button also has a context menu, allowing to pop multiple pages at
                 * once, potentially across multiple navigation views.
                 *
                 * Set {@link HeaderBar.showBackButton} to `FALSE` to disable this behavior
                 * in rare scenarios where it's unwanted.
                 *
                 * ## Split View Integration
                 *
                 * When placed inside {@link NavigationSplitView} or {@link OverlaySplitView},
                 * `AdwHeaderBar` will automatically hide the title buttons other than at the
                 * edges of the window.
                 *
                 * ## Bottom Sheet Integration
                 *
                 * When played inside {@link BottomSheet}, `AdwHeaderBar` will not show the title
                 * unless {@link BottomSheet.showDragHandle} is set to `FALSE`, regardless
                 * of {@link HeaderBar.showTitle}. This only applies to the default title,
                 * titles set with {@link HeaderBar.titleWidget} will still be shown.
                 *
                 * ## Centering Policy
                 *
                 * {@link HeaderBar.centeringPolicy} allows to enforce strict centering of
                 * the title widget. This can be useful for entries inside {@link Clamp}.
                 *
                 * ## Title Buttons
                 *
                 * Unlike `GtkHeaderBar`, `AdwHeaderBar` allows to toggle title button
                 * visibility for each side individually, using the
                 * {@link HeaderBar.showStartTitleButtons} and
                 * {@link HeaderBar.showEndTitleButtons} properties.
                 *
                 * ## CSS nodes
                 *
                 * ```
                 * headerbar
                 * ╰── windowhandle
                 *     ╰── box
                 *         ├── widget
                 *         │   ╰── box.start
                 *         │       ├── windowcontrols.start
                 *         │       ├── widget
                 *         │       │   ╰── [button.back]
                 *         │       ╰── [other children]
                 *         ├── widget
                 *         │   ╰── [Title Widget]
                 *         ╰── widget
                 *             ╰── box.end
                 *                 ├── [other children]
                 *                 ╰── windowcontrols.end
                 * ```
                 *
                 * `AdwHeaderBar`'s CSS node is called `headerbar`. It contains a `windowhandle`
                 * subnode, which contains a `box` subnode, which contains three `widget`
                 * subnodes at the start, center and end of the header bar. The start and end
                 * subnodes contain a `box` subnode with the `.start` and `.end` style classes
                 * respectively, and the center node contains a node that represents the title.
                 *
                 * Each of the boxes contains a `windowcontrols` subnode, see
                 * {@link Gtk.WindowControls} for details, as well as other children.
                 *
                 * When {@link HeaderBar.showBackButton} is `TRUE`, the start box also
                 * contains a node with the name `widget` that contains a node with the name
                 * `button` and `.back` style class.
                 *
                 * ## Accessibility
                 *
                 * `AdwHeaderBar` uses the {@link Gtk.AccessibleRole.group} role.
                 */
                HeaderBar: HeaderBarClass
            }
            

