            interface $Exports {
                /**
                 * An item within {@link SidebarSection}.
                 *
                 * Sidebar items must have a title, set via {@link SidebarItem.title}.
                 *
                 * Sidebar items should, but are not required to, have an icon. Icons can be set
                 * from an icon name, via {@link SidebarItem.iconName}, or a
                 * {@link Gdk.Paintable}, via {@link SidebarItem.iconPaintable}.
                 *
                 * Items can also have subtitles, set with the {@link SidebarItem.subtitle}
                 * property. Subtitles should be used sparingly.
                 *
                 * To add a tooltip, use {@link SidebarItem.tooltip}. Tooltips always use
                 * Pango markup.
                 *
                 * Items can have an arbitrary suffix widget, set with the
                 * {@link SidebarItem.suffix} properties. It will be displayed at the end of
                 * its row, or before the arrow in the {@link Adw.SidebarMode.page} mode.
                 *
                 * To hide or disable the item, use the {@link SidebarItem.visible} and
                 * {@link SidebarItem.enabled} properties respectively.
                 *
                 * To access the items's section, use {@link SidebarItem.section}.
                 *
                 * It's also possible to access the index of the item in both the section and
                 * the sidebar, using {@link SidebarItem.get_section_index} and
                 * {@link SidebarItem.get_index} respectively.
                 *
                 * Dragging content over sidebar items activates them by default. To disable
                 * this behavior, set {@link SidebarItem.dragMotionActivate} to `FALSE`.
                 *
                 * `AdwSidebarItem` is derivable, and applications that need to associate each
                 * page with data can store it in the items themselves  this way.
                 * @since 1.9
                 */
                SidebarItem: SidebarItemClass
            }
            

