            interface $Exports {
                /**
                 * A widget showing a loading spinner.
                 *
                 * <picture>
                 *   <source srcset="spinner-dark.png" media="(prefers-color-scheme: dark)">
                 *   <img src="spinner.png" alt="spinner">
                 * </picture>
                 *
                 * The size of the spinner depends on the available size, never smaller than
                 * 16×16 pixels and never larger than 64×64 pixels.
                 *
                 * Use the {@link Gtk.Widget.halign} and {@link Gtk.Widget.valign}
                 * properties in combination with {@link Gtk.Widget.widthRequest} and
                 * {@link Gtk.Widget.heightRequest} for fine sizing control.
                 *
                 * For example, the following snippet shows the spinner at 48×48 pixels:
                 *
                 * ```xml
                 * <object class="AdwSpinner">
                 *   <property name="halign">center</property>
                 *   <property name="valign">center</property>
                 *   <property name="width-request">48</property>
                 *   <property name="height-request">48</property>
                 * </object>
                 * ```
                 *
                 * See {@link SpinnerPaintable} for cases where using a widget is impractical or
                 * impossible, such as {@link StatusPage.paintable}.
                 *
                 * ## CSS nodes
                 *
                 * `AdwSpinner` has a single node with the name `image` and the style class
                 * `.spinner`.
                 *
                 * ## Accessibility
                 *
                 * `AdwSpinner` uses the {@link Gtk.AccessibleRole.progress-bar} role.
                 * @since 1.6
                 */
                Spinner: SpinnerClass
            }
            

