            interface $Exports {
                /**
                 * A freeform window.
                 *
                 * <picture>
                 *   <source srcset="window-dark.png" media="(prefers-color-scheme: dark)">
                 *   <img src="window.png" alt="window">
                 * </picture>
                 *
                 * The `AdwWindow` widget is a subclass of {@link Gtk.Window} which has no
                 * titlebar area. Instead, {@link ToolbarView} can be used together with
                 * {@link HeaderBar} or {@link Gtk.HeaderBar} as follows:
                 *
                 * ```xml
                 * <object class="AdwWindow">
                 *   <property name="content">
                 *     <object class="AdwToolbarView">
                 *       <child type="top">
                 *         <object class="AdwHeaderBar"/>
                 *       </child>
                 *       <property name="content">
                 *         <!-- ... -->
                 *       </property>
                 *     </object>
                 *   </property>
                 * </object>
                 * ```
                 *
                 * Using {@link Gtk.Window.titlebar} or {@link Gtk.Window.child}
                 * is not supported and will result in a crash. Use {@link Window.content}
                 * instead.
                 *
                 * ## Dialogs
                 *
                 * `AdwWindow` can contain {@link Dialog}. Use {@link Dialog.present} with the
                 * window or a widget within a window to show a dialog.
                 *
                 * ## Breakpoints
                 *
                 * `AdwWindow` can be used with {@link Breakpoint} the same way as
                 * {@link BreakpointBin}. Refer to that widget's documentation for details.
                 *
                 * Example:
                 *
                 * ```xml
                 * <object class="AdwWindow">
                 *   <property name="content">
                 *     <object class="AdwToolbarView">
                 *       <child type="top">
                 *         <object class="AdwHeaderBar"/>
                 *       </child>
                 *       <property name="content">
                 *         <!-- ... -->
                 *       </property>
                 *       <child type="bottom">
                 *         <object class="GtkActionBar" id="bottom_bar">
                 *           <property name="revealed">True</property>
                 *           <property name="visible">False</property>
                 *         </object>
                 *       </child>
                 *     </object>
                 *   </property>
                 *   <child>
                 *     <object class="AdwBreakpoint">
                 *       <condition>max-width: 500px</condition>
                 *       <setter object="bottom_bar" property="visible">True</setter>
                 *     </object>
                 *   </child>
                 * </object>
                 * ```
                 *
                 * When breakpoints are used, the minimum size must be larger than the smallest
                 * UI state. `AdwWindow` defaults to the minimum size of 360×200 px. If that's
                 * too small, set the {@link Gtk.Widget.widthRequest} and
                 * {@link Gtk.Widget.heightRequest} properties manually.
                 *
                 * ## Adaptive Preview
                 *
                 * `AdwWindow` has a debug tool called adaptive preview. It can be opened from
                 * GTK Inspector or by pressing <kbd>Ctrl</kbd>+<kbd>Shift</kbd>+<kbd>M</kbd>,
                 * and controlled via the {@link Window.adaptivePreview} property.
                 */
                Window: WindowClass
            }
            

